const t=[{id:"artisan",name:"Artisan",description:"You are skilled enough in a trade to make a comfortable living and to aspire to mastery of your art.",skillProficiencies:["persuasion","insight"],toolProficiencies:["Artisan's tools"],languages:0,equipment:["Artisan's tools","Traveler's clothes"],feature:{name:"Trade Mark",description:"Your craftsmanship is recognizable by those familiar with your work, and you can leverage your reputation to gain access to clients, materials, and patronage."}},{id:"exile",name:"Exile",description:"Your homeland is barred to you and you wander strange lands.",skillProficiencies:["survival","history"],toolProficiencies:[],languages:1,equipment:["Traveler's clothes","10 days rations"],feature:{name:"Fellow Traveler",description:"You can find others who share your experience of displacement, and they are often willing to offer aid and shelter to a fellow exile."}},{id:"farmer",name:"Farmer",description:"You were raised a farmer, an occupation where the money is short and the work days are long.",skillProficiencies:["nature","animal-handling"],toolProficiencies:[],languages:0,equipment:["Common clothes","Shovel","Mule","5 Supply"],feature:{name:"Bit and Bridle",description:"You have a way with working animals and beasts of burden, able to calm and care for them in ways that earn their trust."}},{id:"gambler",name:"Gambler",description:"You haven't met your match at dice or cards.",skillProficiencies:["deception","insight"],toolProficiencies:["Gaming set"],languages:0,equipment:["Fine clothes","Dice set","Playing card set"],feature:{name:"Lady Luck",description:"You have a knack for games of chance and an intuition for reading other gamblers, granting you an edge in any game you sit down to play."}},{id:"guildmember",name:"Guildmember",description:"It never hurts to be part of a team, and when you're part of a guild opportunities knock at your door.",skillProficiencies:[],toolProficiencies:["Artisan's tools"],languages:0,equipment:["Artisan's tools","Traveler's clothes","Guild badge"],feature:{name:"Guild Business",description:"Your guild membership grants you connections and resources, including lodging and support from fellow guild members in most cities."}},{id:"marauder",name:"Marauder",description:"You were a member of an outlaw band.",skillProficiencies:["survival","intimidation"],toolProficiencies:[],languages:0,equipment:["Traveler's clothes","Signal whistle","Tent"],feature:{name:"Secret Ways",description:"You know hidden paths, smuggler routes, and secret ways through the wilderness that others would never find on their own."}},{id:"sailor",name:"Sailor",description:"You're an experienced mariner with a keen weather eye and a favorite tavern in every port.",skillProficiencies:["athletics","acrobatics"],toolProficiencies:["Navigator's tools"],languages:0,equipment:["Common clothes","Navigator's tools","50 feet of rope"],feature:{name:"Sea Salt",description:"Your experience at sea has earned you the respect of other sailors. You can secure free passage on a sailing ship for yourself and your companions."}},{id:"trader",name:"Trader",description:"You served your apprenticeship among merchants and traders. You've traveled dusty miles and haggled under distant skies.",skillProficiencies:["persuasion","deception"],toolProficiencies:[],languages:0,equipment:["Traveler's clothes","Abacus","Merchant's scale"],feature:{name:"Supply and Demand",description:"You have a keen sense of commerce and can quickly assess the value of goods and find the best deals in any marketplace."}},{id:"urchin",name:"Urchin",description:"You grew up on the streets.",skillProficiencies:["sleight-of-hand","stealth"],toolProficiencies:["Disguise kit"],languages:0,equipment:["Common clothes","Disguise kit"],feature:{name:"Guttersnipe",description:"When you are in a town or city, you can provide a poor lifestyle for yourself and your companions. You know how to get anywhere in town without being spotted by gangs, gossips, or guard patrols."}},{id:"con-artist",name:"Con Artist",description:"You have always had a way with people, understanding what makes them tick and exploiting it for personal gain.",skillProficiencies:["deception","sleight-of-hand"],toolProficiencies:["Disguise kit","Forgery kit"],languages:0,equipment:["Fine clothes","Disguise kit","Tools of the con (ten stoppered bottles filled with colored liquid, a weighted die set, a deck of marked cards, or a signet ring of an imaginary duke)","15 gp"],feature:{name:"Cover Story",description:"You have created a secondary persona that includes documents, mannerisms, a social presence and acquaintances. You can also forge documents including official papers and personal letters, as long as you have seen an example of the kind of document or the handwriting you are trying to copy."}},{id:"scoundrel",name:"Scoundrel",description:"You grew up in poverty in a crowded urban environment, surviving through wit and cunning rather than brute force.",skillProficiencies:["athletics","sleight-of-hand"],toolProficiencies:["Gaming set","Thieves' tools"],languages:0,equipment:["A bag of 1,000 ball bearings","A pet monkey wearing a tiny fez","Common clothes","10 gp"],feature:{name:"Urban Explorer",description:"You are familiar with the layout and rhythms of towns and cities. When you arrive in a new city, you can quickly locate places to stay, where to buy good quality gear, and other facilities. You also excel at evading pursuers through streets and rooftops."},suggestedCharacteristics:{personalityTraits:["Flashing a big smile often gets me out of trouble.","If I can just keep them talking, it will give me time to escape.","I get fidgety if I have to sit still for more than ten minutes or so.","Whatever I do, I try to do it with style and panache.","I don't hold back when there's free food and drink on offer.","Nothing gets me more annoyed than being ignored.","I always sit with my back to the wall and my eyes on the exits.","Why walk down the street when you can run across the rooftops?"],ideals:["Freedom. I bow to no one, and no one tells me what to do. (Chaotic)","Community. We have to take care of each other, because no one else will. (Lawful)","Charity. I steal from the wealthy so that I can help those in need. (Good)","Friendship. Material goods come and go. Bonds of friendship last forever. (Neutral)","Aspiration. I'm going to prove that I'm worthy of a better life. (Any)","Greed. I will do whatever it takes to get what I want. (Evil)"],bonds:["My elder sibling taught me how to find a safe hiding place in the city. This saved my life at least once.","I stole money from someone who couldn't afford to lose it and now they're destitute. One day I'll make it up to them.","The street kids in my town are my true family.","My mother gave me an old brass lamp. I polish it every night before going to sleep.","When I was young, I was too scared to leap from the tallest tower in my hometown onto the hay cart beneath. I'll try again someday.","A city guardsman let me go when they should have arrested me for stealing. I am forever in their debt."],flaws:["If there's a lever to pull, I'll pull it.","It's not stealing if nobody realizes it's gone.","If I don't like the odds, I'm out of there.","I often don't know when to shut up.","I once filched a pipe from a priest. Now I think the god has cursed me.","I grow angry when someone else steals the limelight."]}},{id:"court-servant",name:"Court Servant",description:"Even though you are independent now, you were once a servant to a merchant, noble, regent, or other person of high station.",skillProficiencies:["history","insight"],toolProficiencies:["Artisan's tools"],languages:1,equipment:["Artisan's tools","Unique piece of jewelry","Fine clothes","Handcrafted pipe","20 gp"],feature:{name:"Servant's Invisibility",description:"The art of excellent service requires a balance struck between being always available and yet unobtrusive, and you have mastered it. If you don't perform a visible action, speak, or be spoken to for at least 1 minute, creatures nearby have trouble remembering you are even in the room."},suggestedCharacteristics:{personalityTraits:["Unless I must speak, I hold my breath while serving others.","It takes all my effort not to show the effusive emotions I feel when I help others.","It is getting harder to tolerate the prejudices of those I serve daily.","Though the old ways are hard to give up, I want to be my own boss.","Serving my family and friends is the only thing I truly care about.","City life is killing my soul. I long for the old courtly ways.","It is time for my fellows to wake up and be taken advantage of no longer.","It is the small things that make it all worthwhile."],ideals:["Family. My family comes before all others. (Any)","Service. Serving others is the highest calling. (Lawful)","Sloth. If I can avoid doing work, all the better. (Chaotic)","Compassion. Everyone deserves kindness and care. (Good)","Tradition. The established ways must be preserved. (Lawful)","Joy. Finding happiness in every task is its own reward. (Good)"],bonds:["My family needs me to provide for them.","My kin have served this holding for generations.","I can't read the inscriptions on this odd ring, but it's all I have left of my family.","I'm with the best friends a person can ask for, so why do I feel so lonesome?","I've found a profession where my skills are put to good use.","I found peace in a special garden filled with beautiful life."],flaws:["I would rather serve darkness than serve no one.","I'm afraid of taking risks that might be good for me.","I believe my master's people are superior to all others.","I always do as I'm told, even though sometimes I don't think I should.","I know what's best for everyone, and they'd all be better off if they'd follow my advice.","I can't stand seeing ugly or depressing things."]}},{id:"desert-runner",name:"Desert Runner",description:"You grew up in the desert. As a nomad, you moved from place to place, following the caravan trails.",skillProficiencies:["perception","survival"],toolProficiencies:["Herbalism kit"],languages:1,equipment:["Traveler's clothes","Herbalism kit","Waterskin","10 gp"],feature:{name:"Nomad",description:"Your body is adapted to desert conditions. You can survive on half the water normally required, and you can read the environment to predict natural weather patterns and temperatures for the next 24 hours."},suggestedCharacteristics:{personalityTraits:["I prefer sleeping under the stars to sleeping indoors.","I believe helping travelers in need creates mutual survival bonds.","I am slow to trust strangers but intensely loyal to established friends.","I enthusiastically participate in camel racing whenever possible.","I regularly share campfire stories and poetry.","I dislike remaining in one location beyond two consecutive nights.","I have recently been troubled by recurring dreams requiring investigation.","I experience greater loneliness in crowded cities than in the open desert."],ideals:["Greater Good. It is each person's responsibility to help others. (Good)","Nature. The natural world is more important than any civilization. (Neutral)","Tradition. The stories, legends, and customs of my people must be preserved. (Lawful)","Change. Life is like the seasons, in constant change, and we must change with it. (Chaotic)","Honor. If I dishonor myself, I dishonor my whole tribe. (Any)","Greed. I will do whatever it takes to ensure my own survival. (Evil)"],bonds:["My tribe was slaughtered, and I must find out why and avenge them.","I follow a spiritual path and must complete a sacred quest.","A friend was enslaved, and I must rescue them.","I owe a debt to a nature spirit who saved my life.","I carry a sword passed down through generations; it is my duty to wield it with honor.","I was banished from my homeland and will not rest until I reclaim my place."],flaws:["I prefer the company of camels to most people.","I become loud and belligerent when intoxicated.","When insulted, I fall silent and plot revenge.","I enjoy the thrill of violence more than I should.","I am unreliable in a crisis and tend to freeze.","I once betrayed a member of my tribe, and the guilt haunts me."]}},{id:"destined",name:"Destined",description:"Duty is a complicated, tangled affair, be it filial, political, or civil. You are running toward or away from a significant life responsibility.",skillProficiencies:["history","insight"],toolProficiencies:[],languages:1,equipment:["A dagger, quarterstaff, or spear","Traveler's clothes","Destiny memento","15 gp"],feature:{name:"Reputation of Opportunity",description:"Your quest precedes you, making those in power willing to briefly meet with you. They may offer aid such as travel passage, meals, or lodging, though often with hidden costs or implied requests."},suggestedCharacteristics:{personalityTraits:["I am eager to find my destiny and move forward.","I keep hope's fire burning bright.","I am resigned to fate's inevitability while enjoying the journey.","I am determined by obligation to those who established this path.","I am more afraid of returning to my destiny than exploring the world.","I am bitter about being forced to change my life.","I am proud to be chosen for this rare lifepath.","I am uncertain; I will find my destiny when it finds me."],ideals:["Inevitability. What's coming can't be stopped. (Evil)","Tradition. I am part of a generational cycle that must continue. (Any)","Defiance. No one can make me be something I don't want to be. (Any)","Greater Good. My duty ensures the betterment of my community. (Good)","Power. Success on this path brings personal opportunities. (Chaotic)","Responsibility. I have an obligation regardless of my desire. (Lawful)"],bonds:["The friendships I have made along the journey matter most to me.","My destiny's benefits will strengthen my family.","Others' attempts to alter my decision are offensive to me.","The path to destiny matters as much as the destination.","I'm committed despite uncertainty about success or failure.","My region will suffer without this role fulfilled."],flaws:["If you don't have a destiny, are you really special?","I identify myself as the chosen one.","Fear of commitment underlies everything I do.","I have anxiety about potential failure.","I am indifferent to others' sacrifices for this destiny.","I have a pattern of poor decisions, including running away."]}},{id:"diplomat",name:"Diplomat",description:"You have always found harmonious solutions to conflict. You might have started mediating family conflicts as a child.",skillProficiencies:["insight","persuasion"],toolProficiencies:[],languages:2,equipment:["Fine clothes","Letter of passage from a local authority or traveling papers","20 gp"],feature:{name:"A Friend in Every Port",description:"Your reputation as a peacemaker precedes you, or people recognize your easy demeanor, typically allowing you to attain food and lodging at a discount."},suggestedCharacteristics:{personalityTraits:["I like to travel, meet new people, and learn about different customs.","I intercede in minor squabbles to find common ground on all sides.","I never disparage others, even when they might deserve such treatment.","I always try to make a new friend wherever I travel, and when I return to those areas, I seek out my friends.","I have learned how to damn with faint praise, but I only use it when someone has irked me.","I am not opposed to throwing a bit of coin around to ensure a good first impression.","Even when words fail at the outset, I still try to calm tempers.","I treat everyone as an equal, and I encourage others to do likewise."],ideals:["Harmony. I want everyone to get along. (Good)","Contractual. When I resolve a conflict, I ensure all parties formally acknowledge the resolution. (Lawful)","Selfishness. I use my way with words to benefit myself the most. (Evil)","Freedom. Tyranny is a roadblock to compromise. (Chaotic)","Avoidance. A kind word is preferable to the drawing of a sword. (Any)","Unity. It is possible to achieve a world without borders and without conflict. (Any)"],bonds:["I want to engineer a treaty with far-reaching effects in the world.","I am carrying out someone else's agenda and making favorable arrangements for my benefactor.","A deal I brokered went sour, and I am trying to make amends for my mistake.","My nation treats everyone equitably, and I'd like to bring that enlightenment to other nations.","A traveling orator taught me the power of words, and I want to emulate that person.","I fear a worldwide conflict is imminent, and I want to do all I can to stop it."],flaws:["I always start by appealing to a better nature from those I face, regardless of their apparent hostility.","I assume the best in everyone, even if I have been betrayed by that trust in the past.","I will stand in the way of an ally to ensure conflicts don't start.","I believe I can always talk my way out of a problem.","I chastise those who are rude or use vulgar language.","When I feel I am on the verge of a successful negotiation, I often push my luck to obtain further concessions."]}},{id:"forest-dweller",name:"Forest Dweller",description:"You are a creature of the forest, born and reared under a canopy of green.",skillProficiencies:["nature","survival"],toolProficiencies:["Woodcarver's tools","Herbalism kit"],languages:0,equipment:["Common clothes","Hunting trap","Wood staff","Whetstone","Explorer's pack","5 gp"],feature:{name:"Forester",description:"After 1 hour of observation in a forest, you can identify safe resting locations protected from the elements and nonmagical beasts, and find kindling for a fire."},suggestedCharacteristics:{personalityTraits:["I never forget the hunger of winter; I field dress every kill for survival.","I am lonely only in cities; I am content when alone in the forest.","Walking barefoot enhances my connection to the natural world.","I create my own paths rather than following roads.","I find divine will in nature, not in temples.","I reject artificial standards of hygiene.","I prefer to kill with my hands and teeth over forged weapons.","I have a habit of talking loudly to myself, a holdover from years of isolation."],ideals:["Change. Embrace the seasonal shifts of nature. (Chaotic)","Conservation. Preserve all life wherever possible. (Good)","Acceptance. Be part of the ecosystem, not above it. (Neutral)","Cull. Remove weakness to strengthen the whole. (Evil)","Candor. Be open, plain, and honest in all things. (Any)","Balance. Follow nature's equity in all matters. (Neutral)"],bonds:["I plant trees on my companions' graves.","I am guided by the voice of the forest itself.","I owe my life to the hermit who raised me.","I carry a wooden doll from my childhood.","I respect the eternal Old Ways above all else.","I am driven to protect the natural order."],flaws:["I am poor at compromising and struggle to hold a conversation.","I won't harm beasts without just cause.","I misread social cues and default to fight-or-flight responses.","I enjoy nurturing growth from decay a bit too much.","I am in self-imposed exile for damage I caused to a forest.","I refuse to work alongside anyone who consorts with the undead."]}},{id:"former-adventurer",name:"Former Adventurer",description:"As you belted on your weapons and hoisted the pack onto your back, you never thought you'd become an adventurer again. But the heroic call couldn't be ignored.",skillProficiencies:["perception","survival"],toolProficiencies:[],languages:1,equipment:["A dagger, quarterstaff, or shortsword","Old souvenir from previous adventuring days","Traveler's clothes","50 feet of hempen rope","15 gp"],feature:{name:"Old Friends and Enemies",description:"Your previous career as an adventurer brought you far and you met many people along the way. Acquaintances may help or hinder you based on shared history."},suggestedCharacteristics:{personalityTraits:["I have a thousand stories about every aspect of the adventuring life.","My past is my own, and to the pit with anyone who pushes me about it.","I can endure any hardship without complaint.","I have a list of rules for surviving adventures, and I refer to them often.","It's a dangerous job, and I take my pleasures when I can.","I can't help mentioning all the famous friends I've met before.","Anyone who doesn't recognize me is clearly not someone worth knowing.","I've seen it all. If you don't listen to me, you're going to get us all killed."],ideals:["Strength. Experience tells me there are no rules to war. Only victory matters. (Evil)","Growth. I strive to improve myself and prove my worth to companions and myself. (Any)","Thrill. I am only happy when facing danger with my life on the line. (Any)","Generous. If I can help someone in danger, I will. (Good)","Ambition. I may have lost my renown, but nothing will stop me from reclaiming it. (Chaotic)","Responsibility. Any cost to myself is far less than the price of doing nothing. (Lawful)"],bonds:["I will end the monsters who killed my family and pulled me back into the adventuring life.","A disaster made me retire once. Now I will stop it from happening to anyone else.","My old weapon has been my trusted companion for years. It's my lucky charm.","My family doesn't understand why I became an adventurer again, which is why I send them souvenirs, letters, or sketches of exciting encounters.","I was a famous adventurer once. This time, I will be even more famous, or die trying.","Someone is impersonating me. I will hunt them down and restore my reputation."],flaws:["It's all about me! Haven't you learned that by now?","I think I can identify every weapon and item with just a look.","You think this is bad? Let me tell you about something really frightening.","Sure, I have old foes around every corner, but who doesn't?","I'm getting too old for this.","Seeing the bad side in everything just protects you from inevitable disappointment."]}},{id:"freebooter",name:"Freebooter",description:"You sailed the seas as a freebooter, part of a pirate crew.",skillProficiencies:["athletics","survival"],toolProficiencies:["Navigator's tools","Vehicles (water)"],languages:0,equipment:["Pirate flag","Several tattoos","50 feet of rope","Traveler's clothes","10 gp"],feature:{name:"A Friendly Face in Every Port",description:"Your seafaring reputation grants you shelter and meals in port cities from those familiar with your ship. They may also provide you with useful information about recent goings-on, including which ships have been in and out of port."},suggestedCharacteristics:{personalityTraits:["I am happiest on a gently rocking vessel, gazing at the horizon.","I felt butterflies every time we raised the pirate flag.","I have lovers in multiple ports.","I know an extensive repertoire of swear words and bawdy jokes.","I dream of bathing in a tub of gold.","I enjoy bloody combat the most.","I feel truly alive during storms on deck.","Nothing annoys me more than a badly tied knot."],ideals:["Freedom. The sea is freedom; I will never be caged. (Chaotic)","Greed. Gold is the only thing that matters. (Evil)","Comradery. My crew is my family. (Neutral)","Greater Good. I oppose slavery wherever I find it. (Good)","Code. I follow the pirate code without exception. (Lawful)","Aspiration. One day I will be captain of my own ship. (Any)"],bonds:["I was rescued by anti-slavery pirates and owe them my life.","I have a deep attachment to my former ship.","I was mutinied against and cast overboard; I seek revenge.","I returned from a mysterious voyage with gaps in my memory.","I fell asleep during my watch, and it haunts me to this day.","I must rescue an enslaved former shipmate."],flaws:["I have an irrational fear of deserts.","My excessive drinking often leads to brawls.","I once murdered a shipmate for loot.","I take unnecessary risks for the thrill.","I sold captives to slave traders and feel no remorse.","I am chronically dishonest."]}},{id:"gamekeeper",name:"Gamekeeper",description:"You are comfortable in natural environments, excelling at tracking game and managing herds sustainably.",skillProficiencies:["animal-handling","persuasion"],toolProficiencies:["Leatherworker's tools"],languages:1,equipment:["Leatherworker's tools","Hunting trap","Fishing tackle","Traveler's clothes","10 gp"],feature:{name:"Confirmed Guildmember",description:"Your guild membership enables you to train raptors or hunting dogs as companions through 30 days of work and 2 gp daily expenditure. Companions learn up to six commands and can help sustain your party during overland travel."},suggestedCharacteristics:{personalityTraits:["Nature has lessons to teach us all, and I'm always happy to share them.","Once while out on a hunt, something happened which was very relatable to our current situation.","My friends are my new charges, and I'll make sure they thrive.","Preparation and knowledge are the key to any success.","I've dealt with all sorts of wealthy and noble folk, and I've seen just how spoiled they can be.","I feel like my animals are the only ones who really understand me.","You can train yourself to accomplish anything you put your mind to.","The world shows you everything you need to know if you pay attention to details."],ideals:["Dedication. I do what must be done, no matter the cost. (Evil)","Training. The pursuit of mastery is its own reward. (Any)","Prestige. I seek recognition for my skills. (Any)","Diligent. Hard work and honest effort are the foundations of a good life. (Good)","Nature. The natural world is more important than any civilization. (Chaotic)","Responsibility. I care for those who depend on me. (Lawful)"],bonds:["I understand animals better than people, and the way of the hunter just makes sense.","I take great pride in providing my services to the wealthy and influential.","Natural spaces need to be tended and preserved, and I take joy in doing it.","I need to ensure people know how to manage nature rather than live in ignorance.","Laws are important to prevent nature's overexploitation.","I can be alone in the wilderness and not feel lonely."],flaws:["Individuals can be all right, but civilization is the worst.","The wealthy and nobility are a rot in society.","Things die, either by predators or nature; get used to it.","Everything can be managed if you want it badly enough.","When you make exceptions, you allow unworthy things to survive.","If you don't work hard for something, is it worth anything?"]}},{id:"innkeeper",name:"Innkeeper",description:"You spent time as an innkeeper, tavern keeper, or bartender. You watched them come and go, and now your time for adventure has come.",skillProficiencies:["insight","persuasion"],toolProficiencies:[],languages:2,equipment:["Brewer's supplies or cook's utensils","Dagger or light hammer","Traveler's clothes","20 gp"],feature:{name:"I Know Someone",description:"Through interacting with the wide variety of people who visited your establishment, you gained excellent knowledge of who might be able to perform a particular task, provide the right service, or sell the perfect item."},suggestedCharacteristics:{personalityTraits:["I approach challenges with the precision of cooking, measuring every move.","Using empathy and listening skills yields unexpected benefits.","I can relate a story or tale to any situation.","I am always exploring the world of tastes and flavors.","I solve problems with judicious application of force.","I never pass up a bargaining opportunity.","I demand the finest accommodations and know their worth.","I defuse tense situations through humor or wit."],ideals:["Service. We help others, and in turn, they help us. (Lawful)","Perspective. People will tell you a great deal about themselves if you listen. (Any)","Determination. Perseverance overcomes all obstacles. (Any)","Charity. I help those in need whenever I can. (Good)","Curiosity. The world is worth exploring, even at personal risk. (Chaotic)","Selfish. My skills have value, and I intend to profit from them. (Evil)"],bonds:["I aspire to own and operate a tavern of my own.","I want to preserve my companions' stories for posterity.","I assess the character of others through shared meals.","I've seen life's dregs at the bar, and I refuse to end up like them.","I seek revenge against the one who destroyed my inn.","I want to become legendary in my home city."],flaws:["I tease or criticize those I perceive as less intelligent.","I overindulge in rich food and drink.","I distrust those unwilling to share a drink with me.","I disapprove of violence in bars because I know the consequences.","I have a compulsive need to help every hungry or homeless person.","I am quick to anger when anyone criticizes my cooking."]}},{id:"mercenary-company-scion",name:"Mercenary Company Scion",description:"You descend from a famous line of free company veterans, and your first memory is playing among the tents, training yards, and war rooms of one campaign or another.",skillProficiencies:["athletics","history"],toolProficiencies:["Gaming set","Musical instrument"],languages:1,equipment:["Backpack","Signet ring with family's free company symbol","Musical instrument","Mess kit","Traveler's clothes","20 gp"],feature:{name:"The Family Name",description:"Your family name is well known in the close-knit world of mercenary companies. Members of mercenary companies readily recognize your name and will provide food, drink, and shelter with pleasure or out of fear, depending upon your family's reputation."},suggestedCharacteristics:{personalityTraits:["I am ashamed of my family's reputation and seek to distance myself from their deeds.","I have seen the world and know people everywhere.","I expect the best life has to offer and won't settle for less.","I know stories from a thousand campaigns and can apply them to any situation.","After too many betrayals, I don't trust anyone.","My parents were heroes, and I try to live up to their example.","I have seen the horrors of war; nothing disturbs me anymore.","I truly believe I have a destiny of glory and fame awaiting me."],ideals:["Glory. Only by fighting for the right causes can I achieve true fame and honor. (Good)","Dependable. Once my oath is given, it cannot be broken. (Lawful)","Seeker. Life can be short, so I will live it to the fullest before I die. (Chaotic)","Ruthless. Only the strong survive. (Evil)","Mercenary. If you have gold, I'm your blade. (Neutral)","Challenge. Life is a test, and only by meeting life head on can I prove I am worthy. (Any)"],bonds:["My parent's legacy is a tissue of lies. I will never stop until I uncover the truth.","I am the only one who can uphold the family name.","My companions are my life, and I would do anything to protect them.","I will never forget the betrayal leading to my parent's murder, but I will avenge them.","My honor and reputation are all that matter in life.","I betrayed my family to protect my friend who was a soldier in another free company."],flaws:["I have no respect for those who never signed on to a mercenary company or walked the battlefield.","I cannot bear losing anyone close to me, so I keep everyone at a distance.","Bloody violence is the only way to solve problems.","I caused the downfall of my family's mercenary company.","I am hiding a horrible secret about one of my family's patrons.","I see insults to my honor or reputation in every whisper, veiled glance, and knowing look."]}},{id:"mercenary-recruit",name:"Mercenary Recruit",description:"Every year, the hopeful strive to earn a place in one of the great mercenary companies. You are either in training or gaining field experience before advancement.",skillProficiencies:["athletics","persuasion"],toolProficiencies:["Gaming set"],languages:0,equipment:["Letter of introduction from an old teacher","Gaming set","Traveler's clothes","10 gp"],feature:{name:"Theoretical Experience",description:"You have an encyclopedic knowledge of stories, myths, and legends of famous soldiers, mercenaries, and generals. You can earn meals and lodging by sharing tales, and your youth encourages locals to confide rumors and information."},suggestedCharacteristics:{personalityTraits:["I am thrilled by upcoming combat.","I write my own songs rather than waiting for fame to find me.","I constantly reference famous adventurer legends.","I use humor to manage my fear.","I seek out new weapon techniques and share my knowledge freely.","I prove my worth through hard work and risk-taking.","I view training cessation as a death sentence.","I project false bravery to hide my doubts."],ideals:["Respect. I honor others before expecting honor in return. (Good)","Discipline. Following orders is the foundation of any good company. (Lawful)","Courage. I do what is right regardless of the law. (Chaotic)","Excitement. I live for the thrill of battle. (Neutral)","Power. One day I will give the orders, not follow them. (Evil)","Ambition. I will improve myself regardless of what stands in my way. (Any)"],bonds:["I will avenge my murdered mentor.","I will become the greatest mercenary warrior the world has ever seen.","I trust the lessons of my teacher above all else.","I must repay the sacrifices my family made for me.","I will earn the respect of my companions through facing danger head on.","I possess a hidden map that leads to a magical treasure."],flaws:["I distrust and question authority at every turn.","I ridicule others to hide my own insecurities.","I refuse to show any doubt about my courage.","I am haunted by a childhood monster attack.","I act impulsively without thinking through the consequences.","I create extra work for others to hide my own laziness."]}},{id:"monstrous-adoptee",name:"Monstrous Adoptee",description:"Songs and sagas tell of heroes who, as children, were raised by creatures most view as monsters. You were adopted and raised by non-humanoid creatures.",skillProficiencies:["intimidation","survival"],toolProficiencies:[],languages:1,equipment:["A club, handaxe, or spear","Trinket from pre-adoption life","Traveler's clothes","Collection of bones, shells, or natural objects","5 gp"],feature:{name:"Abnormal Demeanor",description:"You can forage in your adopted parent's terrain type to sustain up to six people daily. Creatures resembling your adopted parents are disposed to hear you out rather than attack immediately."},suggestedCharacteristics:{personalityTraits:["I don't eat living friends, but enemies are fair game.","I view direct eye contact as a dominance challenge.","I understand monsters better than humanoids.","I categorize all creatures as either prey or non-prey.","I use growls and sounds instead of words when possible.","I am fascinated by seemingly inconsequential items.","I blame my monstrous upbringing for my worst behavior.","I behave monstrously despite my normal appearance."],ideals:["Wild. The strong survive and the weak perish; that is the natural order. (Evil)","Insight. Both worlds have much to teach; I will learn from all. (Neutral)","Revenge. Those who abandoned me will regret it. (Any)","Harmony. I will bridge the gap between monsters and humanoids. (Good)","Freedom. I belong to no world and answer to no one. (Chaotic)","Redemption. I will prove that my upbringing does not define me. (Lawful)"],bonds:["I seek to experience everything the world has to offer.","I rely on my companions to help me navigate social situations.","My sibling was kidnapped, and I will find them.","I want to earn acceptance from my birth family.","I am hiding from my adoptive family for reasons of my own.","I am pursued by an enemy of my adoptive family."],flaws:["I prefer my meat raw and still warm.","I collect trophies from defeated foes.","I ignore property laws as a meaningless concept.","I am easily startled by loud noises and bright lights.","I have no respect for those weaker than me in combat.","I view kindness as a weakness to be exploited."]}},{id:"mysterious-origins",name:"Mysterious Origins",description:"Your origins are a mystery even to you. You might recall fragments of your previous life, but you cannot be sure of what is remembered and what is imagined.",skillProficiencies:["deception","survival"],toolProficiencies:["Artisan's tools or musical instrument"],languages:1,equipment:["Mysterious trinket from your past life","Artisan's tools or musical instrument","Common clothes","5 gp"],feature:{name:"Unexpected Acquaintance",description:"Someone from your past will recognize you and offer to aid you or to impede you. This person's identity and relationship depend on your backstory."},suggestedCharacteristics:{personalityTraits:["I am always humming a forgotten song.","I love learning new things and meeting new people.","I am driven to prove my worth and gain recognition.","I dislike crowded or noisy spaces.","I am mistrustful of mages and magic.","I prefer tidiness and organization in all things.","I record my daily experiences in a detailed journal.","I live in the present moment and worry little about the past."],ideals:["Redemption. I will make up for whatever I may have done in the past. (Good)","Independence. I answer to no one but myself. (Chaotic)","Cunning. I use every advantage I can find. (Evil)","Community. We are stronger when we work together. (Lawful)","Fairness. Everyone deserves an equal chance. (Neutral)","Friendship. My companions are the family I have chosen. (Any)"],bonds:["I dream of a loved one's face without remembering the details.","I wear a wedding ring from a forgotten marriage.","I was raised by a mentor following a family tragedy.","I have an unknown enemy who seeks revenge against me.","I bear a significant scar that I know is important, but I cannot remember why.","I owe a debt to someone who cared for me when I was lost."],flaws:["I am jealous of those with happy childhood memories.","I desperately pursue knowledge of my past at any cost.","I am terrified of meeting someone from my forgotten life.","I am unconcerned with future consequences of my actions.","I expect treatment befitting former wealth or power I may have had.","I respond with scorn to anyone who shows me pity."]}},{id:"northern-minstrel",name:"Northern Minstrel",description:"While the tribal warriors residing in the wintry north consider you soft and cowardly, you know the truth: life in northern cities and mead halls is not for the faint of heart.",skillProficiencies:["perception","performance"],toolProficiencies:["Musical instrument"],languages:1,equipment:["Book of songs, poems, and stories","Snowshoes","Musical instrument","Heavy fur-lined cloak","10 gp"],feature:{name:"Northern Historian",description:"After examining a structure for one hour, you can identify its builder type (humans, dwarves, elves, goblins, giants, trolls, or fey) and approximate its age within 500 years."},suggestedCharacteristics:{personalityTraits:["I accept any dare if it will bring me accolades.","I prefer quiet observation over revelry.","I challenge northern reavers to prove their worth.","I seek tales of the raiding season to perform for crowds.","I wish to witness Ragnarok and document my survival.","I enjoy nothing more than mutton, mead, and a captive audience.","I accept that my fate is woven by the gods.","I have mastered the art of deception."],ideals:["Valor. I inspire great deeds that benefit all. (Good)","Greed. I take what I want because I can. (Evil)","Perfection. All deeds improve me and bring me closer to mastery. (Lawful)","Anarchy. I do as I wish, and none can stop me. (Chaotic)","Knowledge. I seek to understand ancient ruins and the workings of fate. (Any)","Pleasure. I indulge without restraint. (Any)"],bonds:["I rely on the support of my peers from the skaldic school.","I am determined to solve the Unanswerable Riddle.","I dream of creating a world-renowned epic.","I once escaped a troll ambush by playing my tagelharpa. Music saved my life.","I must always remain near the ocean.","Mead is my most steadfast companion."],flaws:["I believe retreat is the same as cowardice.","All of my personal tales are complete fabrications.","I punish critics harshly after my performances.","I resent companions whose accomplishments exceed my own.","I once burned a tavern down, and I would do it again.","I cannot accept disagreement and fall into bitter melancholy."]}},{id:"occultist",name:"Occultist",description:"At your core, you are a believer in things others dismiss. The signs abound if you know where to look.",skillProficiencies:["arcana","religion"],toolProficiencies:["Thieves' tools"],languages:2,equipment:["Book of obscure lore","Bottle of black ink","Quill","Leather-bound journal","Bullseye lantern","Common clothes","5 gp"],feature:{name:"Strange Lore",description:"Your connections with esoteric individuals help you locate information about eldritch secrets or dark knowledge. Contacts include information brokers, disgraced scholars, chaotic mages, dangerous cults, or insane priests."},suggestedCharacteristics:{personalityTraits:["I always ask questions, especially if I think I can learn something new.","I believe every superstition I hear and follow their rules fanatically.","The things I know give me nightmares, and not only when I sleep.","Nothing makes me happier than explaining some obscure lore to my friends.","I startle easily.","I perform a host of rituals throughout the day that I believe protect me from occult threats.","I never know when to give up.","The more someone refuses to believe me, the more I am determined to convince them."],ideals:["Domination. With the power I will unearth, I will take my revenge on those who wronged me. (Evil)","Mettle. Each nugget of hidden knowledge I uncover proves my worth. (Any)","Lore. Knowledge is never good or evil; it is simply knowledge. (Neutral)","Redemption. This dark knowledge can be made good if it is used properly. (Good)","Truth. Nothing should be hidden. Truth is all that matters, no matter who it hurts. (Chaotic)","Responsibility. Only by bringing dark lore into the light can we eliminate its threat. (Lawful)"],bonds:["One or more secret organizations are trying to stop me, which means I must be close to the truth.","My studies come before anything else.","No theory, however unbelievable, is worth abandoning without investigation.","I must uncover the truth behind a particular mystery, one my father died to protect.","I travel with my companions because I have reason to believe they are crucial to the future.","I once had a partner in my occult searches who vanished. I am determined to find them."],flaws:["When stressed, I mutter theories to myself, sometimes connecting seemingly unrelated events.","It's not paranoia if they really are out to get me.","I have a habit of lying to hide my theories and discoveries.","I see secrets and mysteries in everything and everyone.","The world is full of dark secrets, and I'm the only one who can safely unearth them.","There is no law or social convention I won't break to further my goals."]}},{id:"crime-syndicate-member",name:"Crime Syndicate Member",description:"Your lifestyle of deceiving-to-survive eventually drew the attention of an organized and dangerous crime syndicate.",skillProficiencies:["deception","stealth"],toolProficiencies:["Thieves' tools"],languages:0,equipment:["Dark common clothes including a hood","Thieves' tools","10 gp"],feature:{name:"A Favor In Turn",description:"You can call in favors from syndicate contacts near centers of criminal activity. A request for a favor can be no longer than 20 words and is passed up the chain to an undisclosed syndicate boss for approval. Debts must be repaid with tasks."}},{id:"elemental-warden",name:"Elemental Warden",description:"Away from the complex political struggles of the massive cities, you've been raised to revere and protect the natural world while policing elemental powers.",skillProficiencies:["nature","survival"],toolProficiencies:["Herbalism kit"],languages:1,equipment:["Staff","Hunting gear (a shortbow with 20 arrows, or a hunting trap)","Traveler's clothes","10 gp"],feature:{name:"Elemental Harmony",description:"Your upbringing surrounded by strong elemental magics has attuned your senses to their chaotic forces. You learn the Prestidigestion cantrip with element-specific minor effects based on your tribe selection (Fire, Water, Earth, or Wind)."}},{id:"fate-touched",name:"Fate-Touched",description:"Many lives find their ways through patterns of fate and destiny. You possess a mysterious influence, with your thread bending the weave of fate around you.",skillProficiencies:[],toolProficiencies:[],languages:0,equipment:[],feature:{name:"Fortune's Grace",description:"Your fate-touched essence occasionally leads surrounding events to shift in your favor. You gain 1 Luck point, as per the Lucky feat."}},{id:"lyceum-student",name:"Lyceum Student",description:"You came up through money or a family of social prestige, as tuition at a lyceum is not inexpensive. Your academic pursuits aim to make a meaningful impact on the world.",skillProficiencies:["arcana","history"],toolProficiencies:[],languages:2,equipment:["Fine clothes","Lyceum student uniform","Writing kit (quill, ink, parchment, penknife)","10 gp"],feature:{name:"Student Privilege",description:"You have access to specialized chambers at the lyceum and allied universities to use tool kits on-site, with potential supervision for advanced crafts. Free access to crafting materials and enchanting tables, subject to approval."}},{id:"recovered-cultist",name:"Recovered Cultist",description:"You escaped a dark cult and now seek redemption. Your time worshipping at the altar of malevolent forces has left its mark on you.",skillProficiencies:["religion","deception"],toolProficiencies:[],languages:1,equipment:["Vestments and a holy symbol from your former cult","Common clothes","15 gp"],feature:{name:"Wicked Awareness",description:"Your time worshipping in secrecy and shadow has left you with insight and keen awareness to those who still operate in such ways. You have advantage on ability checks to discover cult activity in populated areas."}}],a=[{id:"acolyte",name:"Acolyte",description:"You have spent your life in the service of a temple to a specific god or pantheon of gods.",skillProficiencies:["insight","religion"],toolProficiencies:[],languages:2,equipment:["Holy symbol","Prayer book or prayer wheel","Vestments","5 sticks of incense","15 gp"],feature:{name:"Shelter of the Faithful",description:"As an acolyte, you command the respect of those who share your faith, and you can perform the religious ceremonies of your deity."}},{id:"charlatan",name:"Charlatan",description:"You have always had a way with people. You can read their moods, their desires, and quickly find your way to their hearts.",skillProficiencies:["deception","sleight-of-hand"],toolProficiencies:["Disguise kit","Forgery kit"],languages:0,equipment:["Fine clothes","Disguise kit","Tools of the con (ten stoppered bottles filled with colored liquid, a weighted die set, a deck of marked cards, or a signet ring of an imaginary duke)","15 gp"],feature:{name:"False Identity",description:"You have created a second identity that includes documentation, established acquaintances, and disguises that allow you to assume that persona."}},{id:"criminal",name:"Criminal",description:"You are an experienced criminal with a history of breaking the law.",skillProficiencies:["deception","stealth"],toolProficiencies:["Gaming set","Thieves' tools"],languages:0,equipment:["Crowbar","Dark common clothes with hood","15 gp"],feature:{name:"Criminal Contact",description:"You have a reliable and trustworthy contact who acts as your liaison to a network of other criminals."}},{id:"entertainer",name:"Entertainer",description:"You thrive in front of an audience. You know how to entrance them, entertain them, and even inspire them.",skillProficiencies:["acrobatics","performance"],toolProficiencies:["Disguise kit","Musical instrument"],languages:0,equipment:["Musical instrument","Favor of an admirer","Costume","15 gp"],feature:{name:"By Popular Demand",description:"You can always find a place to perform, receiving free lodging and food in exchange for performing each night."}},{id:"folk-hero",name:"Folk Hero",description:"You come from a humble social rank, but you are destined for so much more.",skillProficiencies:["animal-handling","survival"],toolProficiencies:["Artisan's tools","Vehicles (land)"],languages:0,equipment:["Artisan's tools","Shovel","Iron pot","Common clothes","10 gp"],feature:{name:"Rustic Hospitality",description:"Since you come from the ranks of the common folk, you fit in among them with ease. You can find a place to hide, rest, or recuperate among commoners."}},{id:"hermit",name:"Hermit",description:"You lived in seclusion, either in a sheltered community or entirely alone, for a formative part of your life.",skillProficiencies:["medicine","religion"],toolProficiencies:["Herbalism kit"],languages:1,equipment:["Scroll case full of notes","Winter blanket","Herbalism kit","Common clothes","5 gp"],feature:{name:"Discovery",description:"The quiet seclusion of your extended hermitage gave you access to a unique and powerful discovery."}},{id:"noble",name:"Noble",description:"You understand wealth, power, and privilege.",skillProficiencies:["history","persuasion"],toolProficiencies:["Gaming set"],languages:1,equipment:["Fine clothes","Signet ring","Scroll of pedigree","25 gp"],feature:{name:"Position of Privilege",description:"Thanks to your noble birth, people are inclined to think the best of you. You are welcome in high society."}},{id:"outlander",name:"Outlander",description:"You grew up in the wilds, far from civilization and the comforts of town and technology.",skillProficiencies:["athletics","survival"],toolProficiencies:["Musical instrument"],languages:1,equipment:["Staff","Hunting trap","Trophy from animal you killed","Traveler's clothes","10 gp"],feature:{name:"Wanderer",description:"You have an excellent memory for maps and geography, and you can always recall the general layout of terrain."}},{id:"sage",name:"Sage",description:"You spent years learning the lore of the multiverse.",skillProficiencies:["arcana","history"],toolProficiencies:[],languages:2,equipment:["Bottle of black ink","Quill","Small knife","Letter from a dead colleague","Common clothes","10 gp"],feature:{name:"Researcher",description:"When you attempt to learn or recall a piece of lore, if you do not know that information, you often know where and from whom you can obtain it."}},{id:"soldier",name:"Soldier",description:"War has been your life for as long as you care to remember.",skillProficiencies:["athletics","intimidation"],toolProficiencies:["Gaming set","Vehicles (land)"],languages:0,equipment:["Insignia of rank","Trophy taken from a fallen enemy","Bone dice set or playing card set","Common clothes","10 gp"],feature:{name:"Military Rank",description:"You have a military rank from your career as a soldier. Soldiers loyal to your former military organization still recognize your authority."}}],i=[...a,...t];function n(e){return i.find(o=>o.id===e)}export{i as backgrounds,n as getBackgroundById};
